const item = $input.first();
const binary = { ...(item.binary || {}) };
const binaryKeys = Object.keys(binary);

const fileKey =
  binaryKeys.find((key) => key === 'file') ??
  binaryKeys.find((key) => key.startsWith('file')) ??
  binaryKeys[0];

if (!fileKey) {
  throw new Error(
    'No file received from ZapTask. Expected multipart field "file". Binary keys: ' +
      (binaryKeys.join(', ') || 'none'),
  );
}

const raw = item.json?.body ?? item.json ?? {};
const meta = raw.body ?? raw;

return [
  {
    json: {
      operational_document_id: Number(meta.operational_document_id),
      operational_object_id: Number(meta.operational_object_id),
      user_id: Number(meta.user_id),
      company_id: meta.company_id ? Number(meta.company_id) : null,
      mime_type: meta.mime_type || binary[fileKey]?.mimeType || 'application/octet-stream',
      title: meta.title || binary[fileKey]?.fileName || 'document',
      original_filename: binary[fileKey]?.fileName || meta.title || 'document',
      debug_binary_key_used: fileKey,
      is_pdf: String(meta.mime_type || '').includes('pdf'),
      is_image: String(meta.mime_type || '').startsWith('image/'),
    },
    binary: fileKey === 'file' ? binary : { file: binary[fileKey] },
  },
];

